var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"큭! 아무리 공격해도 사라지질 않아!","JPN":"くっ！　いくら攻撃しても消えない！","ENG":"Ugh! These things just won't go away, no matter how much I attack!","TWN":"咳！再怎麼攻擊也打不掉！"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"이 꿈틀거리는 것들은 대체 뭐야?!","JPN":"このくねくねしているモノは何なの？","ENG":"What are these wriggly things anyway?","TWN":"這些在蠕動的怪東西到底是什麼？！"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"이건...... 아트 디렉터님의 분신이에요.","JPN":"これは……アートディレクターさんの分身です。","ENG":"These are... part of the Art Director's body.","TWN":"這是… 美術局長的分身。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"아마 집요하게 달려드는 걸 보면, 언니에게 흥미가 생긴 걸지도......","JPN":"ここまでしつこく襲いかかってくるってことは、お姉ちゃんに興味がわいたのかも……","ENG":"The way they just keep coming at you suggests that she's taken an interest in you...","TWN":"看它執意的一直撲過來，也許是對姐姐產生了興趣……"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"흥미....... 라고?","JPN":"興味……って？","ENG":"Interested... in me?","TWN":" 興趣……？"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SHADOW_NPC_FOOLSDAY_NULL","text":{"KOREA":"당신의 기운이 처음 느껴질 때부터 쭉 예의주시해왔어요.","JPN":"あなたのオーラを初めて感じた時からずっと注視していました。","ENG":"We've monitored you closely ever since we could sense your presence.","TWN":"從第一次感受到你的氣息時，我就開始一直密切關注著你。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"SHADOW_NPC_FOOLSDAY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SHADOW_NPC_FOOLSDAY_NULL","text":{"KOREA":"당신은 우리와는 완전히 다른 사고와 지식을 가지고 있군요?","JPN":"あなたは我々とはまったく違う思考と知識を持っていますね？","ENG":"Your reasoning and knowledge are completely different from ours, aren't they?","TWN":"你擁有和我們完全不同的思考和知識呢？"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"SHADOW_NPC_FOOLSDAY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SHADOW_NPC_FOOLSDAY_NULL","text":{"KOREA":"그 머릿속에 들어있는 독특한 화풍들은 우리 것으로 만들기에 충분히 매력적이에요.","JPN":"その頭の中に入っている独特な画風は、我々のものにしたいほど十分魅力的です。","ENG":"Those unique art styles in your head are appealing enough to make our own.","TWN":"將你腦中的獨特畫風，製作並成為我們自己的，真是非常的有魅力呢。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"SHADOW_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","text":{"KOREA":"당신은......?","JPN":"あなたは……？","ENG":"You're…?","TWN":"你是……？"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"아트 디렉터님!","JPN":"アートディレクターさん！","ENG":"Art Director!","TWN":"美術局長大人！"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","text":{"KOREA":"저 사람이 아트 디렉터라고? 몸에서 이상한 게 자라고 있는데?","JPN":"あの人がアートディレクター？　身体から変なモノが生えてるけど？","ENG":"That's the Art Director? With all that stuff growing out of her body?","TWN":"那個人就是美術局長？在身上長了奇怪的東西呢？"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"아트 디렉터님은...... 이미 한 번 나이트워커가 된 적이 있던 분이에요.","JPN":"アートディレクターさんは……すでに一度ナイトウォーカーになっているんです。","ENG":"The Art Director... She was once a Night Worker herself.","TWN":"美術局長是個…… 曾經變成過夜行者一次的人。"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"하지만 야근에 완전히 침식해 이성을 잃지 않고, 오히려 그 힘을 자기 것으로 흡수한 케이스죠.","JPN":"でも、残業に完全に侵食されても理性を失わず、むしろその力を自分のものとして吸収した珍しいケースです。","ENG":"But instead of giving in to the dark energy of overtime, she absorbed its powers as her own.","TWN":"因爲加班被夜行者完全侵蝕後，不但沒有失去理性，反而吸收成自己的力量。"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","text":{"KOREA":"나이트워커의 힘을...... 자신이 흡수했다고?","JPN":"ナイトウォーカーの力を……自分に吸収した？","ENG":"She absorbed... the Night Worker's power?","TWN":"將夜行者的力量…… 吸收成自己的？"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SHADOW_NPC_FOOLSDAY_NULL","text":{"KOREA":"당신처럼 흥미로운 데이터는 처음 봤어요.","JPN":"あなたのような興味深いデータは初めてです。","ENG":"We've never seen data so curiously interesting as yours.","TWN":"我第一次看像你這樣有趣的數據呢。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"SHADOW_NPC_FOOLSDAY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SHADOW_NPC_FOOLSDAY_NULL","text":{"KOREA":"자, 두려워 말고 저희와 함께 해요.","JPN":"さあ、恐れる必要はありません。我々と一緒になりましょう。","ENG":"Come, join us. There's nothing to be afraid of.","TWN":"來，不要害怕，和我們一起吧。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"SHADOW_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SHADOW_NPC_FOOLSDAY_NULL","text":{"KOREA":"이 계약서에 사인을 하고, 우리 게임과 하나가 되는 거예요.","JPN":"この契約書にサインをして、我が社のゲームと一つになるのです。","ENG":"Sign this contract and become one with our game.","TWN":"在這個契約書上簽個名，跟我們的遊戲合為一體吧。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"SHADOW_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};